      return {
        day: this.weekdayLabel(currentDate || previousDate),
        currentDate,
        currentRevenue,
        previousDate,
        previousRevenue,
        delta: `${this.signed(delta, 2)} 元`,
        absoluteDelta: Math.abs(delta),
      };
    })
      .sort((left, right) => right.absoluteDelta - left.absoluteDelta)
      .map

